package com.example.oidc.service;

import com.example.oidc.config.OidcClientConfig;
import com.example.oidc.model.TokenResponse;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.util.UriComponentsBuilder;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.Map;
import java.util.UUID;

@Service
public class OidcClientService {

    public static final String SESSION_STATE = "OIDC_STATE";
    public static final String SESSION_NONCE = "OIDC_NONCE";
    public static final String SESSION_USER = "OIDC_USER";

    private final OidcClientConfig config;
    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    public OidcClientService(OidcClientConfig config, RestTemplate restTemplate, ObjectMapper objectMapper) {
        this.config = config;
        this.restTemplate = restTemplate;
        this.objectMapper = objectMapper;
    }

    public String buildAuthorizationUrl(HttpSession session) {
        String state = UUID.randomUUID().toString();
        String nonce = UUID.randomUUID().toString();
        session.setAttribute(SESSION_STATE, state);
        session.setAttribute(SESSION_NONCE, nonce);

        return UriComponentsBuilder
                .fromHttpUrl(config.getAuthorizationEndpoint())
                .queryParam("response_type", "code")
                .queryParam("client_id", config.getClientId())
                .queryParam("redirect_uri", config.getRedirectUri())
                .queryParam("scope", config.getScope())
                .queryParam("state", state)
                .queryParam("nonce", nonce)
                .build(true)
                .toUriString();
    }

    public TokenResponse exchangeCodeForTokens(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));
        headers.setBasicAuth(config.getClientId(), config.getClientSecret(), StandardCharsets.UTF_8);

        MultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", config.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(form, headers);
        ResponseEntity<TokenResponse> response = restTemplate.exchange(
                config.getTokenEndpoint(),
                HttpMethod.POST,
                request,
                TokenResponse.class
        );
        return response.getBody();
    }

    public Map<String, Object> fetchUserInfo(String accessToken) {
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));

        HttpEntity<Void> request = new HttpEntity<>(headers);
        ResponseEntity<String> response = restTemplate.exchange(
                config.getUserinfoEndpoint(),
                HttpMethod.GET,
                request,
                String.class
        );
        try {
            return objectMapper.readValue(response.getBody(), new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse userinfo response", e);
        }
    }

    public Map<String, Object> parseIdTokenClaims(String idToken) {
        try {
            String[] parts = idToken.split("\\.");
            if (parts.length < 2) {
                throw new IllegalArgumentException("Invalid id_token");
            }
            byte[] payload = Base64.getUrlDecoder().decode(parts[1]);
            return objectMapper.readValue(payload, new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse id_token claims", e);
        }
    }

    public boolean validateState(HttpSession session, String state) {
        Object expected = session.getAttribute(SESSION_STATE);
        return expected != null && expected.equals(state);
    }

    public boolean validateNonce(HttpSession session, Map<String, Object> claims) {
        Object expected = session.getAttribute(SESSION_NONCE);
        Object actual = claims.get("nonce");
        return expected != null && expected.equals(actual);
    }

    public String createCodeVerifier() {
        byte[] code = new byte[32];
        new SecureRandom().nextBytes(code);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(code);
    }

    public String createCodeChallenge(String verifier) {
        try {
            byte[] digest = MessageDigest.getInstance("SHA-256").digest(verifier.getBytes(StandardCharsets.US_ASCII));
            return Base64.getUrlEncoder().withoutPadding().encodeToString(digest);
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }
}

