package com.example.oidc.web;

import com.example.oidc.model.OidcUserSession;
import com.example.oidc.model.TokenResponse;
import com.example.oidc.security.OidcAuthenticationToken;
import com.example.oidc.service.OidcClientService;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.Map;

@Component
public class OidcCallbackFilter extends OncePerRequestFilter {

    private final OidcClientService oidcClientService;

    public OidcCallbackFilter(OidcClientService oidcClientService) {
        this.oidcClientService = oidcClientService;
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        return !"/oidc/callback".equals(request.getRequestURI());
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {
        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Missing session");
            return;
        }

        String code = request.getParameter("code");
        String state = request.getParameter("state");
        String error = request.getParameter("error");

        if (error != null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "OIDC error: " + error);
            return;
        }

        if (code == null || state == null) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing code/state");
            return;
        }

        if (!oidcClientService.validateState(session, state)) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Invalid state");
            return;
        }

        TokenResponse tokenResponse = oidcClientService.exchangeCodeForTokens(code);
        if (tokenResponse == null || tokenResponse.getIdToken() == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Missing token response");
            return;
        }

        Map<String, Object> claims = oidcClientService.parseIdTokenClaims(tokenResponse.getIdToken());
        if (!oidcClientService.validateNonce(session, claims)) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Invalid nonce");
            return;
        }

        Map<String, Object> userInfo = tokenResponse.getAccessToken() != null
                ? oidcClientService.fetchUserInfo(tokenResponse.getAccessToken())
                : Map.of();

        OidcUserSession userSession = new OidcUserSession();
        userSession.setSubject(asString(claims.get("sub")));
        userSession.setUsername(resolveUsername(claims, userInfo));
        userSession.setEmail(resolveEmail(claims, userInfo));
        userSession.setAccessToken(tokenResponse.getAccessToken());
        userSession.setIdToken(tokenResponse.getIdToken());
        userSession.setRefreshToken(tokenResponse.getRefreshToken());
        userSession.setClaims(claims);
        userSession.setUserInfo(userInfo);

        session.setAttribute(OidcClientService.SESSION_USER, userSession);
        SecurityContextHolder.getContext().setAuthentication(new OidcAuthenticationToken(userSession));
        response.sendRedirect("/");
    }

    private String resolveUsername(Map<String, Object> claims, Map<String, Object> userInfo) {
        String preferred = asString(claims.get("preferred_username"));
        if (preferred != null) return preferred;
        preferred = asString(userInfo.get("preferred_username"));
        if (preferred != null) return preferred;
        String name = asString(claims.get("name"));
        if (name != null) return name;
        name = asString(userInfo.get("name"));
        if (name != null) return name;
        return asString(claims.get("sub"));
    }

    private String resolveEmail(Map<String, Object> claims, Map<String, Object> userInfo) {
        String email = asString(claims.get("email"));
        if (email != null) return email;
        return asString(userInfo.get("email"));
    }

    private String asString(Object value) {
        return value == null ? null : String.valueOf(value);
    }
}

package com.example.oidc.web;

import com.example.oidc.model.OidcUserSession;
import com.example.oidc.service.OidcClientService;
import jakarta.servlet.http.HttpSession;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class HomeController {

    @GetMapping("/")
    public Map<String, Object> home(HttpSession session) {
        Map<String, Object> response = new LinkedHashMap<>();
        Object user = session.getAttribute(OidcClientService.SESSION_USER);
        if (user instanceof OidcUserSession oidcUser) {
            response.put("authenticated", true);
            response.put("subject", oidcUser.getSubject());
            response.put("username", oidcUser.getUsername());
            response.put("email", oidcUser.getEmail());
            response.put("claims", oidcUser.getClaims());
            response.put("userinfo", oidcUser.getUserInfo());
        } else {
            response.put("authenticated", false);
            response.put("login", "/login");
        }
        return response;
    }

    @GetMapping("/me")
    public Map<String, Object> me(HttpSession session) {
        Object user = session.getAttribute(OidcClientService.SESSION_USER);
        if (user instanceof OidcUserSession oidcUser) {
            Map<String, Object> response = new LinkedHashMap<>();
            response.put("subject", oidcUser.getSubject());
            response.put("username", oidcUser.getUsername());
            response.put("email", oidcUser.getEmail());
            response.put("claims", oidcUser.getClaims());
            response.put("userinfo", oidcUser.getUserInfo());
            return response;
        }
        throw new IllegalStateException("No authenticated user");
    }
}

